const serpData = $input.item.json;
const kwData = $('Get Opportunity Keywords').item.json;

const topUrls = (serpData.organic_results || []).slice(0, 5).map(r => r.link).filter(Boolean);

return [{ json: {
  projectName: kwData.project_name,
  keyword: kwData.keyword,
  ourPosition: kwData.current_position,
  ourUrl: kwData.url_ranking,
  searchVolume: kwData.search_volume,
  topUrls
}}];

const data = $input.item.json;

// Build the analysis prompt
const urlList = data.topUrls.map((url, i) => `Page ${i+1}: ${url}`).join('\n');
const ourUrl = data.ourUrl || 'Not ranked yet';

const prompt = `Analyse these web pages for the keyword "${data.keyword}".

Competitor pages to analyse:
${urlList}

Our page: ${ourUrl}

Provide a JSON analysis with these exact fields:
{
  "topics_missing": ["topic1", "topic2"], // topics competitors cover that we don't
  "questions_missing": ["question1", "question2"], // FAQs competitors answer that we don't
  "entities_missing": ["entity1", "entity2"], // brands, places, concepts mentioned by competitors
  "word_count_gap": 500, // estimated words we need to add
  "priority_recommendation": "one sentence action"
}

Return ONLY valid JSON, no other text.`;

return [{ json: { ...data, claudePrompt: prompt } }];

const claudeData = $input.item.json;
const inputData = $('Build Claude Prompt').item.json;

let analysis = {};
try {
  const rawText = claudeData.content?.[0]?.text || '{}';
  const jsonMatch = rawText.match(/\{[\s\S]*\}/);
  analysis = jsonMatch ? JSON.parse(jsonMatch[0]) : {};
} catch(e) {
  analysis = { topics_missing: [], questions_missing: [], entities_missing: [], word_count_gap: 0 };
}

// Priority score: (avg_competitor_pos - our_pos) × (search_volume / 100)
const avgCompPos = 3; // average of top 5
const priorityScore = Math.round((avgCompPos - (inputData.ourPosition || 15)) * ((inputData.searchVolume || 100) / 100) * -1);

return [{ json: {
  projectName: inputData.projectName,
  keyword: inputData.keyword,
  ourUrl: inputData.ourUrl,
  ourPosition: inputData.ourPosition,
  competitorUrls: inputData.topUrls,
  topicsMissing: analysis.topics_missing || [],
  questionsMissing: analysis.questions_missing || [],
  entitiesMissing: analysis.entities_missing || [],
  wordCountGap: analysis.word_count_gap || 0,
  priorityScore: Math.max(0, priorityScore)
}}];

// Post top 5 opportunities to Slack
const allItems = $input.all();
const gaps = allItems.map(i => i.json).sort((a, b) => b.priorityScore - a.priorityScore).slice(0, 5);

let msg = `*🔍 Content Gap Opportunities — ${new Date().toDateString()}*\n\n`;

gaps.forEach((gap, i) => {
  msg += `*${i+1}. ${gap.projectName} — "${gap.keyword}"* (Priority: ${gap.priorityScore})\n`;
  msg += `   Current pos: #${gap.ourPosition || 'Not ranked'} | Words to add: ~${gap.wordCountGap}\n`;
  if (gap.topicsMissing?.length > 0) {
    msg += `   Missing topics: ${gap.topicsMissing.slice(0, 3).join(', ')}\n`;
  }
  msg += '\n';
});

msg += '_Run WF-SEO-04 to create optimised content for any of these._';

return [{ json: { summaryText: msg } }];
